```python
import chess
import chess.svg
from termcolor import colored, cprint

# Initialize the board and game state
board = chess.Board()
game_over = False
current_player = "white"

def print_board():
    print(colored(board, attrs=['bold']))
    print("Current Player:", current_player)

def get_move():
    move_str = input(f"Player {current_player}, enter your move (e.g., e2-e4): ")
    try:
        move = chess.Move.from_uci(move_str)
        if move in board.legal_moves:
            return move
        else:
            print("Invalid move. Please try again.")
            return get_move()
    except ValueError:
        print("Invalid move format. Please enter moves in UCI format (e.g., e2-e4).")
        return get_move()

def play_game():
    global game_over, current_player
    while not game_over:
        print_board()
        move = get_move()
        board.push(move)

        if board.is_checkmate():
            print_board()
            print(f"Player {current_player.upper()} wins by checkmate!")
            game_over = True
        elif board.is_stalemate():
            print_board()
            print("Stalemate! Game over.")
            game_over = True
        else:
            current_player = "white" if current_player == "black" else "black"

if __name__ == "__main__":
    play_game()
```

